mapper.sql:
LEFT JOIN (
    SELECT DISTINCT fsa.form_num form_num FROM t_form_share_auth fsa

    ( (fsa.auth_value=#{shareUserId} and fsa.auth_type='personal')

        OR (fsa.auth_value in

            #{shareDeptId}

        AND fsa.auth_type='department')
    )

) sa ON sa.form_num = ys.form_num

    INNER JOIN (
        SELECT DISTINCT yd.ys_form_num, category_ids FROM bid_ys_detail yd


                yd.name LIKE CONCAT ('%', #{acceptanceCondition}, '%')


    ) detail ON detail.ys_form_num = ys.form_num

INNER JOIN common_form cf ON ys.form_num = cf.form_num AND cf.is_valid = 1


        AND cf.current_step = #{currentStep}


        AND cf.audit_status = #{auditStatus}





        ys.form_num LIKE #{ysFormNumKey}


        and ys.form_num in

            #{item}




        AND ys.po_form_num LIKE #{orderFormNumKey}



        AND ys.supplier_name LIKE #{supplierNameKey}



        AND ys.our_subject LIKE #{ourSubjectKey}


            AND ys.creator_no = #{userId}


            AND detail.category_ids IN

                #{item}



        AND ys.create_time >= #{startTime}


        AND  ys.create_time <= #{endTime}

